/**
 * @name Request parameters reflected in response (XSS via redirect/error)
 * @description HTTP request parameters or URI components echoed back to response
 * @kind path-problem
 * @problem.severity error
 * @id java/request-param-to-response
 * @tags security
 *       external/cwe/cwe-079
 */
import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module ReflectedXssConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // Response output streams
    exists(MethodCall mc |
      (
        mc.getMethod().hasName("write") or
        mc.getMethod().hasName("println") or
        mc.getMethod().hasName("print") or
        mc.getMethod().hasName("append")
      ) and
      (
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.io", "Writer") or
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.io", "OutputStream") or
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.io", "PrintStream")
      ) and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // Response builder via JAX-RS
    exists(MethodCall mc |
      mc.getMethod().hasName("entity") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // HttpServletResponse sendRedirect
    exists(MethodCall mc |
      mc.getMethod().hasName("sendRedirect") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module ReflectedXssFlow = TaintTracking::Global<ReflectedXssConfig>;
import ReflectedXssFlow::PathGraph

from ReflectedXssFlow::PathNode source, ReflectedXssFlow::PathNode sink
where ReflectedXssFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "User input flows to HTTP response without encoding (potential XSS) at $@.", source.getNode(), "user input"

/**
 * @name OAuthFlows redirect_uri reflected in error response without encoding
 * @description OAuth redirect_uri or client_id flows into location/entity response
 * @kind path-problem
 * @problem.severity error
 * @id java/oauth-flows-redirect-uri-xss
 * @tags security
 *       external/cwe/cwe-079
 *       external/cwe/cwe-116
 */
import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module OAuthFlowsRedirectConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // location() in JAX-RS response builder - redirect with user data
    exists(MethodCall mc |
      mc.getMethod().hasName("location") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // Response.temporaryRedirect or seeOther
    exists(MethodCall mc |
      (mc.getMethod().hasName("temporaryRedirect") or mc.getMethod().hasName("seeOther")) and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // String concatenation result passed to entity() in OAuthFlows
    exists(MethodCall mc |
      mc.getMethod().hasName("entity") and
      mc.getEnclosingCallable().getDeclaringType().hasQualifiedName("org.keycloak.services.resources.flows", "OAuthFlows") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module OAuthFlowsRedirectFlow = TaintTracking::Global<OAuthFlowsRedirectConfig>;
import OAuthFlowsRedirectFlow::PathGraph

from OAuthFlowsRedirectFlow::PathNode source, OAuthFlowsRedirectFlow::PathNode sink
where OAuthFlowsRedirectFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "OAuth user input flows to redirect/response location at $@.", source.getNode(), "user input"

/**
 * @name User input in redirect URL without encoding (open redirect / XSS)
 * @description OAuth redirect_uri or other user-controlled URL params used unencoded in HTML responses
 * @kind path-problem
 * @problem.severity error
 * @id java/oauth-redirect-xss
 * @tags security
 *       external/cwe/cwe-079
 *       external/cwe/cwe-116
 */
import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module OAuthRedirectXssConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // JAX-RS Response.entity() calls - inline HTML with user data
    exists(MethodCall mc |
      mc.getMethod().hasName("entity") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // sendRedirect with user-controlled data
    exists(MethodCall mc |
      mc.getMethod().hasName("sendRedirect") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // setHeader with user-controlled data
    exists(MethodCall mc |
      mc.getMethod().hasName("setHeader") and
      sink.asExpr() = mc.getArgument(1)
    )
  }
}

module OAuthRedirectXssFlow = TaintTracking::Global<OAuthRedirectXssConfig>;
import OAuthRedirectXssFlow::PathGraph

from OAuthRedirectXssFlow::PathNode source, OAuthRedirectXssFlow::PathNode sink
where OAuthRedirectXssFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "User input flows to redirect/response header/entity at $@.", source.getNode(), "user input"
